@startuml
skinparam classAttributeIconSize 0
skinparam classFontStyle italic
skinparam classBackgroundColor #F5F5F5
skinparam classBorderColor #333333
skinparam classFontColor #333333
skinparam interfaceBackgroundColor #F5F5F5
skinparam interfaceBorderColor #333333
skinparam interfaceFontColor #333333
skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeCBorderColor #333333
skinparam stereotypeCFontColor #333333
skinparam stereotypeIBackgroundColor #D1C4E9
skinparam stereotypeIBorderColor #333333
skinparam stereotypeIFontColor #333333

interface "Printer" as Printer {
  + void print(Document)
}

interface "Scanner" as Scanner {
  + void scan(Document)
}

class "SimplePrinter" as SimplePrinter {
  + void print(Document)
}

class "SimplePrinterScanner" as SimplePrinterScanner {
  + void print(Document)
  + void scan(Document)
}

SimplePrinter ..|> Printer
SimplePrinterScanner ..|> Printer
SimplePrinterScanner ..|> Scanner

@enduml
